local sFile=tSet:Section({Title="File Management",Icon="folder",Box=true})
local cfgN="XKID_Config_V2"local curCfg="No config"
sFile:Input({Title="Config Name",Value="XKID_Config_V2",Callback=function(v)cfgN=v end})
local function SCF()if E.wf then pcall(function()if not isfolder("XKID_HUB")then makefolder("XKID_HUB")end local d={Move={ws=ST.Move.ws,jp=ST.Move.jp,flyS=ST.Move.flyS,aws=ST.Move.aws},ESP={tm=ST.ESP.tm,md=ST.ESP.md,hl=ST.ESP.hl},Sec={sl=ST.Sec.sl,al=ST.Sec.al},HF={pw=ST.HF.pw,md=ST.HF.md},SS={md=SSs.md,rd=SSs.rd,he=SSs.he,sp=SSs.sp},CF={r=ST.CF.r,g=ST.CF.g,b=ST.CF.b,st=ST.CF.st,ct=ST.CF.ct,br=ST.CF.br,ex=ST.CF.ex,bl=ST.CF.bl,bs=ST.CF.bs,ti=ST.CF.ti}}writefile("XKID_HUB/"..cfgN..".json",HS:JSONEncode(d))N("Config","Saved: "..cfgN,2,"save")end)else N("Config","Executor tidak support save",2,"circle-alert")end end
local function LCF(s)if s=="No config"then return end pcall(function()if E.rf and isfile and isfile("XKID_HUB/"..s..".json")then local d=HS:JSONDecode(readfile("XKID_HUB/"..s..".json"))if d then if d.Move then ST.Move.ws=d.Move.ws or 16 ST.Move.jp=d.Move.jp or 50 ST.Move.flyS=d.Move.flyS or 60 ST.Move.aws=d.Move.aws or 16 local h=GH()if h then h.WalkSpeed=ST.Move.ws h.UseJumpPower=true h.JumpPower=ST.Move.jp end end if d.ESP then ST.ESP.tm=d.ESP.tm or"Bottom"ST.ESP.md=d.ESP.md or 300 ST.ESP.hl=d.ESP.hl or false end if d.Sec and d.Sec.sl~=ST.Sec.sl then TSL(d.Sec.sl)end if d.HF then ST.HF.pw=d.HF.pw or 10000 ST.HF.md=d.HF.md or"Spin"end if d.SS then SSs.md=d.SS.md or"Manual"SSs.rd=d.SS.rd or 8 SSs.he=d.SS.he or 3 SSs.sp=d.SS.sp or 1 end if d.CF then for k,v in pairs(d.CF)do ST.CF[k]=v end ACF()end N("Config","Loaded: "..s,2,"folder-open")end end end)end
sFile:Button({Title="Save Config",Callback=SCF})
local cfgD=sFile:Dropdown({Title="Load Config",Values=GCL(),Callback=function(s)curCfg=s LCF(s)end})
sFile:Button({Title="Delete Config",Callback=function()if curCfg~="No config"and curCfg~=""and E.lf then pcall(function()if isfile and delfile and isfile("XKID_HUB/"..curCfg..".json")then delfile("XKID_HUB/"..curCfg..".json")pcall(function()cfgD:Refresh(GCL(),true)end)curCfg="No config"N("Config","Deleted",2,"trash-2")end end)end end})
sFile:Button({Title="Refresh Files",Callback=function()pcall(function()cfgD:Refresh(GCL(),true)end)N("Config","Files refreshed",1.5,"folder")end})
local sLike=tSet:Section({Title="Auto Like (Smart)",Icon="heart",Box=true})
