pcall(function()settings().Rendering.QualityLevel=Enum.QualityLevel.Level02 end)
F(120)
task.spawn(function()task.wait(0.5)SAFK()task.wait(2)getgenv()._XKID_UI_LOADING=false N("System","XKID V2.1 AKTIF — Ready",3,"rocket")N("Anti AFK","AUTO ACTIVATED (7min Jump)",2,"shield-check")end)